export const ENGINE_CSS = `/* See scrolly-waypoint package for full styles */
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
html{font-size:16px;-webkit-font-smoothing:antialiased}
body{font-family:"Inter",system-ui,sans-serif;background:#080c14;color:#e2e4ea;overflow-x:hidden}
#map{position:fixed;inset:0;z-index:0}
.vignette{position:fixed;inset:0;z-index:1;pointer-events:none;background:radial-gradient(ellipse at center,transparent 55%,rgba(4,6,16,0.65) 100%)}
.scroll-track{position:relative;z-index:2;pointer-events:none}
.preloader{position:fixed;inset:0;z-index:9999;display:flex;flex-direction:column;align-items:center;justify-content:center;background:#080c14;transition:opacity .6s ease,visibility .6s ease}
.preloader.hidden{opacity:0;visibility:hidden;pointer-events:none}
.preloader-text{font-size:.7rem;font-weight:500;letter-spacing:.25em;text-transform:uppercase;color:rgba(226,228,234,.5);margin-bottom:2rem}
.preloader-dots{display:flex;gap:6px;margin-bottom:1.5rem}
.preloader-dots span{width:6px;height:6px;border-radius:50%;background:rgba(226,228,234,.4);animation:pulse-dot 1.4s ease-in-out infinite}
.preloader-dots span:nth-child(2){animation-delay:.2s}
.preloader-dots span:nth-child(3){animation-delay:.4s}
.preloader-bar{width:120px;height:2px;background:rgba(226,228,234,.08);border-radius:2px;overflow:hidden;position:relative}
.preloader-bar::after{content:"";position:absolute;inset:0;background:linear-gradient(90deg,transparent,rgba(226,228,234,.4) 50%,transparent);animation:shimmer 1.5s ease-in-out infinite}
.waypoint-overlay{position:fixed;bottom:2rem;left:2rem;z-index:10;width:clamp(260px,28vw,380px);background:rgba(4,6,18,.85);backdrop-filter:blur(20px) saturate(1.4);border:1px solid rgba(96,165,250,.3);border-radius:4px;overflow:hidden;opacity:0;transform:translateX(-20px);pointer-events:none;transition:opacity .45s ease,transform .45s ease}
.waypoint-overlay.active{opacity:1;transform:translateX(0);pointer-events:auto}
.waypoint-overlay.exiting{opacity:0;transform:translateX(-20px);pointer-events:none}
.corner-brackets{position:absolute;inset:0;pointer-events:none;z-index:3}
.corner{position:absolute;width:14px;height:14px}
.corner.tl{top:-1px;left:-1px;border-top:2px solid currentColor;border-left:2px solid currentColor}
.corner.tr{top:-1px;right:-1px;border-top:2px solid currentColor;border-right:2px solid currentColor}
.corner.bl{bottom:-1px;left:-1px;border-bottom:2px solid currentColor;border-left:2px solid currentColor}
.corner.br{bottom:-1px;right:-1px;border-bottom:2px solid currentColor;border-right:2px solid currentColor}
.overlay-photo{position:relative;width:100%;aspect-ratio:16/9;overflow:hidden;background:linear-gradient(135deg,rgba(20,24,36,.8),rgba(10,14,24,.9))}
.overlay-photo img{width:100%;height:100%;object-fit:cover;display:block}
.scanlines{position:absolute;inset:0;background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,.06) 2px,rgba(0,0,0,.06) 4px);pointer-events:none;z-index:1}
.photo-gradient{position:absolute;inset:0;pointer-events:none;z-index:2}
.scan-bar{position:absolute;left:0;right:0;height:2px;z-index:3;animation:scan-line 3.5s ease-in-out infinite}
.overlay-text{padding:1rem 1.15rem .85rem}
.overlay-label{font-family:"Playfair Display",Georgia,serif;font-weight:700;font-size:1.15rem;line-height:1.25;color:#f0f1f5;margin-bottom:.45rem}
.overlay-desc{font-size:.82rem;line-height:1.6;color:rgba(226,228,234,.65);margin-bottom:.75rem}
.overlay-footer{display:flex;align-items:center;justify-content:space-between;padding-top:.6rem;border-top:1px solid rgba(96,165,250,.12)}
.overlay-coords{font-family:"Courier New",monospace;font-size:.65rem;color:rgba(226,228,234,.35)}
.overlay-live{font-family:"Courier New",monospace;font-size:.6rem;letter-spacing:.08em;text-transform:uppercase}
.wp-marker{display:flex;flex-direction:column;align-items:center;pointer-events:none}
.wp-marker-dot{width:10px;height:10px;border-radius:50%;background:rgba(255,255,255,.9);box-shadow:0 0 0 3px rgba(255,255,255,.2),0 0 12px rgba(255,255,255,.3);animation:pulse-marker 2.5s ease-in-out infinite}
.wp-marker-label{margin-top:6px;padding:3px 8px;font-family:"Inter",sans-serif;font-size:.65rem;font-weight:500;color:rgba(255,255,255,.85);background:rgba(4,6,18,.7);backdrop-filter:blur(8px);border:1px solid rgba(255,255,255,.1);border-radius:3px;white-space:nowrap}
.finale-screen{position:fixed;inset:0;z-index:100;display:flex;align-items:center;justify-content:center;background:rgba(4,6,16,.92);opacity:0;visibility:hidden;pointer-events:none;transition:opacity .8s ease,visibility .8s ease}
.finale-screen.active{opacity:1;visibility:visible;pointer-events:auto}
.finale-vignette{position:absolute;inset:0;background:radial-gradient(ellipse at center,transparent 30%,rgba(4,6,16,.6) 100%);pointer-events:none}
.finale-content{position:relative;z-index:1;text-align:center;max-width:600px;padding:2rem;animation:finale-in 1s ease .2s both}
.finale-tagline{font-size:.7rem;font-weight:500;letter-spacing:.3em;text-transform:uppercase;color:rgba(192,132,252,.6);margin-bottom:1.25rem}
.finale-headline{font-family:"Playfair Display",Georgia,serif;font-weight:700;font-size:clamp(2rem,5vw,3.5rem);line-height:1.15;color:#f0f1f5;margin-bottom:1rem}
.finale-subtext{font-size:1rem;line-height:1.7;color:rgba(226,228,234,.55);margin-bottom:2rem}
.finale-line{width:48px;height:2px;background:linear-gradient(90deg,transparent,rgba(192,132,252,.5),transparent);margin:0 auto}
@keyframes pulse-dot{0%,100%{opacity:.3;transform:scale(.8)}50%{opacity:1;transform:scale(1)}}
@keyframes pulse-marker{0%,100%{box-shadow:0 0 0 3px rgba(255,255,255,.2),0 0 12px rgba(255,255,255,.3);transform:scale(1)}50%{box-shadow:0 0 0 6px rgba(255,255,255,.08),0 0 20px rgba(255,255,255,.15);transform:scale(1.15)}}
@keyframes scan-line{0%{top:-2px}100%{top:100%}}
@keyframes shimmer{0%{transform:translateX(-100%)}100%{transform:translateX(100%)}}
@keyframes finale-in{0%{opacity:0;transform:translateY(16px)}100%{opacity:1;transform:translateY(0)}}
@media(max-width:640px){.waypoint-overlay{bottom:0;left:0;right:0;width:100%;border-radius:8px 8px 0 0;max-height:55vh}.waypoint-overlay.active{transform:translateY(0)}.waypoint-overlay:not(.active){transform:translateY(100%)}}
@media(prefers-reduced-motion:reduce){*,*::before,*::after{animation-duration:.01ms!important;transition-duration:.01ms!important}}`;

